import React, { useEffect, useState } from "react";
import database from "./firebase";
import { ref, onValue } from "firebase/database";

function App() {
  const [leftFoot, setLeftFoot] = useState(null);
  const [rightFoot, setRightFoot] = useState(null);

  useEffect(() => {
    const dbRef = ref(database);

    const unsubscribe = onValue(dbRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        setLeftFoot(data.leftFoot || null);
        setRightFoot(data.rightFoot || null);
      }
    });

    return () => unsubscribe();
  }, []);

  const renderFootData = (footData, label) => {
    if (!footData) return <p>{label}: No data</p>;

    return (
      <div style={{ marginBottom: "20px" }}>
        <h2>{label}</h2>
        <p><strong>Timestamp:</strong> {footData.timestamp}</p>
        <p><strong>Force:</strong> {footData.force} N</p>

        <h4>Accelerometer</h4>
        <ul>
          <li>X: {footData.accel?.x}</li>
          <li>Y: {footData.accel?.y}</li>
          <li>Z: {footData.accel?.z}</li>
        </ul>

        <h4>Gyroscope</h4>
        <ul>
          <li>X: {footData.gyro?.x}</li>
          <li>Y: {footData.gyro?.y}</li>
          <li>Z: {footData.gyro?.z}</li>
        </ul>
      </div>
    );
  };

  return (
    <div style={{ padding: 20, fontFamily: "Arial" }}>
      <h1>Foot Sensor Data</h1>
      {renderFootData(leftFoot, "Left Foot")}
      {renderFootData(rightFoot, "Right Foot")}
    </div>
  );
}

export default App;
